  1→import React, { useRef, useState } from "react";
  2→import ReCAPTCHA from "react-google-recaptcha";
  3→
  4→const captchaKey = import.meta.env.VITE_CAPTCHA_KEY;
  5→const captchaSecret = import.meta.env.VITE_CAPTCHA_SECRET;
  6→const serverlUrl = import.meta.env.VITE_SERVER_URL;
  7→
  8→export default function ContactForm() {
  9→  const captchaRef = useRef();
 10→  const [formValue, setFormValue] = useState({
 11→    firstName: "",
 12→    lastName: "",
 13→    email: "",
 14→    company: "",
 15→    phone: "",
 16→    textarea: "",
 17→  });
 18→  const [formError, setFormError] = useState({});
 19→  const [submit, setSubmit] = useState(false);
 20→  const [loading, setLoading] = useState(false);
 21→  const [captchaError, setCaptchaError] = useState(false);
 22→
 23→  const handleSubmit = async (e) => {
 24→    e.preventDefault();
 25→    setLoading(true);
 26→    setFormError(validateForm(formValue));
 27→
 28→    if (Object.keys(validateForm(formValue)).length > 0) {
 29→      setLoading(false);
 30→      return null;
 31→    } else {
 32→      let captchaToken = captchaRef.current?.getValue();
 33→      if (captchaToken.length === 0) {
 34→        setCaptchaError("ReCaptcha is mandatory");
 35→        setLoading(false);
 36→        return;
 37→      }
 38→      window.scrollTo(0, 0);
 39→      const verify = await verifyCaptcha(captchaToken);
 40→      captchaRef.current?.reset();
 41→      if (verify) {
 42→        setSubmit(true);
 43→        setFormValue({
 44→          firstname: "",
 45→          lastname: "",
 46→          email: "",
 47→          message: "",
 48→        });
 49→        setCaptchaError("");
 50→        setLoading(false);
 51→      } else {
 52→        setSubmit(false);
 53→        setFormValue({
 54→          firstname: "",
 55→          lastname: "",
 56→          email: "",
 57→          message: "",
 58→        });
 59→        setCaptchaError("");
 60→        setLoading(false);
 61→      }
 62→    }
 63→  };
 64→
 65→  const handleValidation = (e) => {
 66→    const { name, value } = e.target;
 67→    setFormValue({ ...formValue, [name]: value });
 68→  };
 69→
 70→  const verifyCaptcha = async (captchaToken) => {
 71→    try {
 72→      const response = await fetch(serverlUrl, {
 73→        method: "POST",
 74→        body: JSON.stringify({
 75→          secret: captchaSecret,
 76→          captchaToken,
 77→        }),
 78→        headers: {
 79→          "Content-Type": "application/json",
 80→        },
 81→      });
 82→      if (response.status === 200) {
 83→        return true;
 84→      } else {
 85→        return false;
 86→      }
 87→    } catch (error) {
 88→      console.error("Could not verify captcha!", error.message);
 89→      return false;
 90→    }
 91→  };
 92→  const validateForm = (value) => {
 93→    let errors = {};
 94→    const emailRegex = /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/;
 95→    const numberRegex = /\d/;
 96→    if (!value.firstName) {
 97→      errors.firstName = "Please enter first name!";
 98→    } else if (value.firstName && value.firstName.length < 3) {
 99→      errors.firstName = "First name is too short";
100→    }
101→    if (!value.lastName) {
102→      errors.lastName = "Please enter last name!";
103→    } else if (value.lastName && value.lastName.length < 3) {
104→      errors.lastName = "Last name is too short";
105→    }
106→    if (!value.email) {
107→      errors.email = "Please enter email!";
108→    } else if (!emailRegex.test(value.email)) {
109→      errors.email = "Please enter valid email!";
110→    }
111→    if (!value.company) {
112→      errors.company = "Please enter company!";
113→    } else if (value.company && value.company.length < 3) {
114→      errors.company = "Please enter a valid company name";
115→    }
116→    if (!value.phone) {
117→      errors.phone = "Please enter phone number!";
118→    } else if (!numberRegex.test(value.phone)) {
119→      errors.phone = "Please enter valid phone number!";
120→    }
121→    if (!value.textarea) {
122→      errors.textarea = "Please enter message!";
123→    } else if (value.textarea && value.textarea.length < 10) {
124→      errors.textarea = "The message should be min. 10 characters";
125→    }
126→
127→    return errors;
128→  };
129→
130→  return (
131→    <React.Fragment>
132→      {loading ? (
133→        <div role="status">
134→          <svg
135→            aria-hidden="true"
136→            className="w-40 h-40 mt-6 text-gray-200 animate-spin dark:text-gray-600 fill-purple-600"
137→            viewBox="0 0 100 101"
138→            fill="none"
139→            xmlns="http://www.w3.org/2000/svg">
140→            <path
141→              d="M100 50.5908C100 78.2051 77.6142 100.591 50 100.591C22.3858 100.591 0 78.2051 0 50.5908C0 22.9766 22.3858 0.59082 50 0.59082C77.6142 0.59082 100 22.9766 100 50.5908ZM9.08144 50.5908C9.08144 73.1895 27.4013 91.5094 50 91.5094C72.5987 91.5094 90.9186 73.1895 90.9186 50.5908C90.9186 27.9921 72.5987 9.67226 50 9.67226C27.4013 9.67226 9.08144 27.9921 9.08144 50.5908Z"
142→              fill="currentColor"
143→            />
144→            <path
145→              d="M93.9676 39.0409C96.393 38.4038 97.8624 35.9116 97.0079 33.5539C95.2932 28.8227 92.871 24.3692 89.8167 20.348C85.8452 15.1192 80.8826 10.7238 75.2124 7.41289C69.5422 4.10194 63.2754 1.94025 56.7698 1.05124C51.7666 0.367541 46.6976 0.446843 41.7345 1.27873C39.2613 1.69328 37.813 4.19778 38.4501 6.62326C39.0873 9.04874 41.5694 10.4717 44.0505 10.1071C47.8511 9.54855 51.7191 9.52689 55.5402 10.0491C60.8642 10.7766 65.9928 12.5457 70.6331 15.2552C75.2735 17.9648 79.3347 21.5619 82.5849 25.841C84.9175 28.9121 86.7997 32.2913 88.1811 35.8758C89.083 38.2158 91.5421 39.6781 93.9676 39.0409Z"
146→              fill="currentFill"
147→            />
148→          </svg>
149→          <span className="sr-only">Loading...</span>
150→        </div>
151→      ) : submit && Object.keys(formError).length === 0 ? (
152→        <p className="font-medium text-green-600 text-lg py-10">
153→          Thank you submitting your request. We will review your message and
154→          contact you shortly!
155→        </p>
156→      ) : (
157→        <form
158→          onSubmit={handleSubmit}
159→          className="mt-9 grid grid-cols-1 gap-y-6 sm:grid-cols-2 sm:gap-x-8 text-white">
160→          <section>
161→            <label
162→              htmlFor="firstName"
163→              className="block text-sm font-medium text-white">
164→              First name *
165→            </label>
166→            <section className="mt-1">
167→              <input
168→                type="text"
169→                value={formValue.firstName}
170→                onChange={handleValidation}
171→                name="firstName"
172→                id="first-name"
173→                autoComplete="given-name"
174→                className="text-white p-2 border rounded-md border-gray-300 block w-full sm:text-sm focus:ring-grape-500 focus:border-grape-500 "
175→              />
176→              <span className="text-red-400">{formError.firstName}</span>
177→            </section>
178→          </section>
179→          <section>
180→            <label
181→              htmlFor="lastName"
182→              className="block text-sm font-medium text-white">
183→              Last name *
