199→            <label
200→              htmlFor="email"
201→              className="block text-sm font-medium text-white">
202→              Email *
203→            </label>
204→            <section className="mt-1">
205→              <input
206→                id="email"
207→                name="email"
208→                value={formValue.email}
209→                onChange={handleValidation}
210→                type="text"
211→                autoComplete="email"
212→                className="text-white p-2 border rounded-md border-gray-300 block w-full  sm:text-sm focus:ring-grape-500 focus:border-grape-500 "
213→              />
214→              <span className="text-red-400">{formError.email}</span>
